package src.blocks.woody.org.apache.cocoon.woody.formmodel;

public class FieldDefinitionBuilder extends AbstractDatatypeWidgetDefinitionBuilder { public WidgetDefinition buildWidgetDefinition ( Element widgetElement ) throws Exception { FieldDefinition fieldDefinition = new FieldDefinition ( ) ; buildWidgetDefinition ( fieldDefinition , widgetElement ) ; return fieldDefinition ; } protected void buildWidgetDefinition ( FieldDefinition fieldDefinition , Element widgetElement ) throws Exception { setLocation ( widgetElement , fieldDefinition ) ; setId ( widgetElement , fieldDefinition ) ; Element datatypeElement = DomHelper . getChildElement ( widgetElement , Constants . WD_NS , "datatype" ) ; if ( datatypeElement == null ) { throw new Exception ( "A nested datatype element is required for the widget at " + DomHelper . getLocation ( widgetElement ) ) ; } Datatype datatype = datatypeManager . createDatatype ( datatypeElement , false ) ; fieldDefinition . setDatatype ( datatype ) ; buildSelectionList ( widgetElement , fieldDefinition ) ; Iterator iter = buildEventListeners ( widgetElement , "on-value-changed" , ValueChangedListener . class ) . iterator ( ) ; while ( iter . hasNext ( ) ) { fieldDefinition . addValueChangedListener ( ( ValueChangedListener ) iter . next ( ) ) ; } setDisplayData ( widgetElement , fieldDefinition ) ; setValidators ( widgetElement , fieldDefinition ) ; boolean required = DomHelper . getAttributeAsBoolean ( widgetElement , "required" , false ) ; fieldDefinition . setRequired ( required ) ; } }